import { useEffect, useState, useRef } from 'react';
import { Mail, Github, Linkedin, Sparkles, BookOpen } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

const phrasesEn = ['Cybersecurity Enthusiast','AI & Gen AI Practitioner','Web Developer','Network Enthusiast','MIS Student'];
const phrasesAr = ['متحمس للأمن السيبراني','ممارس للذكاء الاصطناعي','مطور ويب','متحمس للشبكات','طالب نظم معلومات'];

// Animated counter hook
function useCounter(target, duration = 1500, start = false) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime = null;
    const step = (ts) => {
      if (!startTime) startTime = ts;
      const progress = Math.min((ts - startTime) / duration, 1);
      setVal(Math.floor(progress * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [target, duration, start]);
  return val;
}

export default function Hero() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const phrases = lang === 'ar' ? phrasesAr : phrasesEn;

  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);
  const [counterStarted, setCounterStarted] = useState(false);
  const heroRef = useRef(null);

  // Start counter when hero is visible
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setCounterStarted(true); obs.disconnect(); }
    }, { threshold: 0.3 });
    if (heroRef.current) obs.observe(heroRef.current);
    return () => obs.disconnect();
  }, []);

  const certCount = useCounter(20, 1200, counterStarted);

  useEffect(() => { setText(''); setCi(0); setPi(0); setDel(false); }, [lang]);

  useEffect(() => {
    const phrase = phrases[pi];
    const timer = setTimeout(() => {
      if (!del) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) { setTimeout(() => setDel(true), 1800); return; }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) { setDel(false); setPi(p => (p + 1) % phrases.length); setCi(0); return; }
        setCi(c => c - 1);
      }
    }, del ? 42 : 88);
    return () => clearTimeout(timer);
  }, [ci, pi, del, phrases]);

  const bg     = dark ? '#0f0f14' : '#fdfcf9';
  const ink    = dark ? '#f0f0f8' : '#1a1a2e';
  const muted  = dark ? 'rgba(255,255,255,0.5)' : '#5a5a72';
  const amber  = '#f0a500';

  return (
    <section id="hero" ref={heroRef}
      style={{ background: bg, minHeight: '100vh' }}
      className="grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden transition-colors duration-300">

      <div className="blob-hero w-[560px] h-[560px] bg-amber opacity-[0.07] top-[-100px] right-[-130px]" />
      <div className="blob-hero-2 w-[300px] h-[300px] bg-teal opacity-[0.05] bottom-[-50px] left-[28%]" />

      {/* LEFT */}
      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0">
        <p className="text-lg mb-1" style={{ color: muted, animation: 'fadeUp .6s ease both' }}>{tr.hiIm}</p>

        <h1 className="font-serif-display leading-[1.02] tracking-tight" style={{ animation: 'fadeUp .6s .08s ease both' }}>
          <span className="block text-5xl md:text-7xl" style={{ color: ink }}>Kareem Basem</span>
          <em className="block text-5xl md:text-7xl not-italic font-serif-display" style={{ color: amber }}>Fathi.</em>
        </h1>

        <div className="flex items-center gap-2 mt-5 text-sm font-medium" style={{ animation: 'fadeUp .6s .16s ease both' }}>
          <span style={{ color: amber }} className="font-bold">→</span>
          <span className="font-semibold" style={{ color: ink }}>{text}</span>
          <span style={{ color: amber }} className="animate-[ping2_1s_step-end_infinite]">|</span>
        </div>

        <p className="mt-4 text-[0.95rem] leading-[1.8] max-w-[440px]"
          style={{ color: muted, animation: 'fadeUp .6s .24s ease both' }}>
          {tr.heroDesc}
        </p>

        {/* Currently Learning badge */}
        <div className="mt-4 inline-flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-semibold"
          style={{
            background: 'rgba(42,157,143,0.10)', border: '1px solid rgba(42,157,143,0.28)',
            color: '#2a9d8f', animation: 'fadeUp .6s .30s ease both'
          }}>
          <BookOpen size={12} />
          {lang === 'ar' ? '📚 يتعلم الآن: Google Cybersecurity Certificate (6/9)' : '📚 Currently: Google Cybersecurity Certificate (6/9)'}
        </div>

        <div className="flex gap-3 flex-wrap mt-5" style={{ animation: 'fadeUp .6s .32s ease both' }}>
          <a href="#projects"
            className="px-6 py-3 font-semibold text-sm rounded-full transition-all hover:-translate-y-1"
            style={{ background: amber, color: '#fff', boxShadow: `0 4px 20px ${amber}44` }}
            onMouseEnter={e => e.currentTarget.style.boxShadow = `0 8px 28px ${amber}55`}
            onMouseLeave={e => e.currentTarget.style.boxShadow = `0 4px 20px ${amber}44`}>
            {lang === 'ar' ? 'استعرض مشاريعي' : 'Explore Projects'}
          </a>
          <a href="#contact"
            className="px-6 py-3 font-semibold text-sm rounded-full transition-all hover:-translate-y-1"
            style={{ ...glass(dark), color: dark ? 'rgba(255,255,255,0.8)' : ink }}>
            {tr.getInTouch}
          </a>
          <a href="/assets/kareem-cv.pdf" download="Kareem_Basem_CV.pdf"
            className="px-6 py-3 font-semibold text-sm rounded-full transition-all hover:-translate-y-1"
            style={{ background:'rgba(240,165,0,0.10)', border:'1px solid rgba(240,165,0,0.28)', color:amber }}>
            {lang === 'ar' ? '⬇ CV' : '⬇ CV'}
          </a>
        </div>

        <div className="flex items-center gap-3 mt-6" style={{ animation: 'fadeUp .6s .40s ease both' }}>
          <span className="text-xs uppercase tracking-wider font-medium" style={{ color: muted }}>{tr.findMe}</span>
          {[
            { href:'https://www.linkedin.com/in/karem-basem', Icon:Linkedin },
            { href:'https://github.com/Kareem-Basem', Icon:Github },
            { href:'mailto:karemalwy1@gmail.com', Icon:Mail },
          ].map(({ href, Icon }, i) => (
            <a key={i} href={href} target={href.startsWith('http') ? '_blank' : undefined} rel="noreferrer"
              className="w-9 h-9 rounded-full flex items-center justify-center transition-all hover:-translate-y-0.5 hover:text-amber"
              style={{ ...glass(dark), color: muted }}>
              <Icon size={15}/>
            </a>
          ))}
        </div>
      </div>

      {/* RIGHT — Photo */}
      <div className="hidden md:flex flex-col items-center gap-5 relative z-10" style={{ animation: 'fadeUp .7s .2s ease both' }}>
        <div className="relative w-[320px] h-[320px] float">
